import boto3
from botocore.exceptions import BotoCoreError, ClientError

def publish_message_to_sqs(queue_url, user_data):
    sqs = boto3.client('sqs')

    try:
        response = sqs.send_message(
            QueueUrl=queue_url,
            DelaySeconds=10,
            MessageAttributes={},
            MessageBody=(user_data)
        )
        print(f"Message sent to SQS. Message ID: {response['MessageId']}")
    except (BotoCoreError, ClientError) as e:
        print(f"Failed to send message to SQS: {e}")

# Example usage
queue_url = 'https://sqs.your-region.amazonaws.com/your-account-id/your-queue-name'
user_data = {
    "email": "example@example.com",
    "phone_number": "+1234567890",
    "address": "123 Example St, Example City, Example Country"
}

publish_message_to_sqs(queue_url, str(user_data))